import org.assertj.core.api.Assertions.assertThat
import org.junit.Before
import org.junit.Test
import org.mockito.Mock
import org.mockito.MockitoAnnotations
import org.mockito.kotlin.never
import org.mockito.kotlin.verify
import org.mockito.kotlin.whenever
import org.wordpress.android.BaseUnitTest
import org.wordpress.android.ui.domains.management.newdomainsearch.NewDomainSearchViewModel.UiState
import org.wordpress.android.ui.domains.management.newdomainsearch.domainsfetcher.NewDomainsSearchRepository
import org.wordpress.android.ui.domains.management.newdomainsearch.domainsfetcher.NewDomainsSearchRepository.DomainsResult
import org.wordpress.android.ui.domains.management.newdomainsearch.domainsfetcher.ProposedDomain
import org.wordpress.android.util.analytics.AnalyticsTrackerWrapper

@ExperimentalCoroutinesApi
class NewDomainSearchViewModelStaleRequestTest : BaseUnitTest() {
    @Mock
    private lateinit var analyticsTracker: AnalyticsTrackerWrapper

    @Mock
    private lateinit var repository: NewDomainsSearchRepository

    private lateinit var viewModel: NewDomainSearchViewModel

    @Before
    fun setUp() {
        MockitoAnnotations.openMocks(this)
        viewModel = NewDomainSearchViewModel(
            mainDispatcher = testDispatcher(),
            analyticsTracker = analyticsTracker,
            newDomainsSearchRepository = repository
        )
    }

    @Suppress("MaxLineLength")
    @Test
    fun `GIVEN slow first request and fast second request WHEN searching THEN only latest results are shown`() =
        test {
            val uiStates = mutableListOf<UiState>()
            val job = launch { viewModel.uiStateFlow.toList(uiStates) }

            val firstDomain = ProposedDomain(1, "first.com", "100", null, true)
            val secondDomain = ProposedDomain(2, "second.com", "200", null, true)

            // Simulate a slow first request
            whenever(repository.searchForDomains("first")).thenAnswer {
                delay(500) // Slow response
                DomainsResult.Success(listOf(firstDomain))
            }

            // Simulate a fast second request
            whenever(repository.searchForDomains("second")).thenAnswer {
                delay(100) // Fast response
                DomainsResult.Success(listOf(secondDomain))
            }

            // Trigger first search
            viewModel.onSearchQueryChanged("first")
            delay(250) // Wait for debounce

            // Trigger second search (this should cancel the first)
            viewModel.onSearchQueryChanged("second")

            // Wait for everything to complete
            advanceUntilIdle()

            // The first request should have been cancelled, so we should never see firstDomain results
            val populatedStates = uiStates.filterIsInstance<UiState.PopulatedDomains>()

            // We should only have the second domain results
            assertThat(populatedStates).hasSize(1)
            assertThat(populatedStates.last().domains).containsExactly(secondDomain)
            assertThat(populatedStates.last().domains).doesNotContain(firstDomain)

            job.cancel()
        }

    @Suppress("MaxLineLength")
    @Test
    fun `GIVEN multiple rapid searches WHEN latest search completes THEN UI shows latest results only`() =
        test {
            val uiStates = mutableListOf<UiState>()
            val job = launch { viewModel.uiStateFlow.toList(uiStates) }

            val firstDomain = ProposedDomain(1, "a.com", "100", null, true)
            val secondDomain = ProposedDomain(2, "ab.com", "200", null, true)
            val thirdDomain = ProposedDomain(3, "abc.com", "300", null, true)

            // All requests take different times
            whenever(repository.searchForDomains("a")).thenAnswer {
                delay(600)
                DomainsResult.Success(listOf(firstDomain))
            }

            whenever(repository.searchForDomains("ab")).thenAnswer {
                delay(400)
                DomainsResult.Success(listOf(secondDomain))
            }

            whenever(repository.searchForDomains("abc")).thenAnswer {
                delay(200)
                DomainsResult.Success(listOf(thirdDomain))
            }

            // Trigger searches with enough delay to pass debounce
            viewModel.onSearchQueryChanged("a")
            delay(300)
            viewModel.onSearchQueryChanged("ab")
            delay(300)
            viewModel.onSearchQueryChanged("abc")

            advanceUntilIdle()

            // Only the third (latest) request should complete successfully
            val populatedStates = uiStates.filterIsInstance<UiState.PopulatedDomains>()

            // We should only see the result from the last search
            assertThat(populatedStates.last().domains).containsExactly(thirdDomain)

            // The first two requests should have been cancelled before they could update the UI
            // So their searchForDomains calls were started but cancelled
            verify(repository).searchForDomains("a")
            verify(repository).searchForDomains("ab")
            verify(repository).searchForDomains("abc")

            job.cancel()
        }

    @Suppress("MaxLineLength")
    @Test
    fun `GIVEN new search starts before previous completes WHEN previous search would complete THEN previous results are not emitted`() =
        test {
            val uiStates = mutableListOf<UiState>()
            val job = launch { viewModel.uiStateFlow.toList(uiStates) }

            val staleDomain = ProposedDomain(1, "stale.com", "100", null, true)
            val freshDomain = ProposedDomain(2, "fresh.com", "200", null, true)

            // First request is slow
            whenever(repository.searchForDomains("stale")).thenAnswer {
                delay(1000)
                DomainsResult.Success(listOf(staleDomain))
            }

            // Second request is fast
            whenever(repository.searchForDomains("fresh")).thenReturn(
                DomainsResult.Success(listOf(freshDomain))
            )

            viewModel.onSearchQueryChanged("stale")
            delay(300) // Wait for first search to start

            viewModel.onSearchQueryChanged("fresh")
            advanceUntilIdle()

            val populatedStates = uiStates.filterIsInstance<UiState.PopulatedDomains>()

            // Should only contain fresh results, not stale
            val allDomains = populatedStates.flatMap { it.domains }
            assertThat(allDomains).contains(freshDomain)
            assertThat(allDomains).doesNotContain(staleDomain)

            job.cancel()
        }

    @Suppress("MaxLineLength")
    @Test
    fun `GIVEN search cancelled mid-flight WHEN new search starts THEN only new search results are shown`() =
        test {
            val uiStates = mutableListOf<UiState>()
            val job = launch { viewModel.uiStateFlow.toList(uiStates) }

            val cancelledDomain = ProposedDomain(1, "cancelled.com", "100", null, true)
            val completedDomain = ProposedDomain(2, "completed.com", "200", null, true)

            whenever(repository.searchForDomains("cancelled")).thenAnswer {
                delay(800)
                DomainsResult.Success(listOf(cancelledDomain))
            }

            whenever(repository.searchForDomains("completed")).thenAnswer {
                delay(100)
                DomainsResult.Success(listOf(completedDomain))
            }

            // Start first search
            viewModel.onSearchQueryChanged("cancelled")
            delay(260) // Just past debounce, search started

            // Start second search that should cancel the first
            viewModel.onSearchQueryChanged("completed")
            advanceUntilIdle()

            // Verify we never see the cancelled domain in the UI
            val populatedStates = uiStates.filterIsInstance<UiState.PopulatedDomains>()
            val finalState = populatedStates.last()

            assertThat(finalState.domains).containsExactly(completedDomain)

            // Verify stale results don't appear in any state
            populatedStates.forEach { state ->
                assertThat(state.domains).doesNotContain(cancelledDomain)
            }

            job.cancel()
        }
}
"}

