            )
            whenever(repository.searchForDomains("second")).thenReturn(
                DomainsResult.Success(listOf(secondDomain))
            )

            // Start first search
            viewModel.onSearchQueryChanged("first")
            delay(260) // Just past debounce, first search would be starting

            // Start second search (should cancel first if still running)
            viewModel.onSearchQueryChanged("second")
            advanceUntilIdle()

            // Both searches may be initiated, but only second should update UI
            verify(repository, atMost(1)).searchForDomains("first")
            verify(repository).searchForDomains("second")

            // UI should only show second search results
            val populatedStates = uiStates.filterIsInstance<UiState.PopulatedDomains>()
            val finalDomains = populatedStates.last().domains

            assertThat(finalDomains).containsExactly(secondDomain)
            assertThat(finalDomains).doesNotContain(firstDomain)

            job.cancel()
        }

