    @Test
    fun `GIVEN error in first search and success in second WHEN searches complete THEN UI shows second result`() =
        test {
            val uiStates = mutableListOf<UiState>()
            val job = launch { viewModel.uiStateFlow.toList(uiStates) }

            val successDomain = ProposedDomain(1, "success.com", "100", null, true)

            whenever(repository.searchForDomains("error")).thenReturn(DomainsResult.Error)
            whenever(repository.searchForDomains("success")).thenReturn(
                DomainsResult.Success(listOf(successDomain))
            )

