import org.wordpress.android.ui.domains.management.newdomainsearch.domainsfetcher.ProposedDomain
import org.wordpress.android.util.analytics.AnalyticsTrackerWrapper

/**
 * Tests to verify that stale domain search requests are properly cancelled when a new search starts.
 * This ensures that only the most recent search results update the UI, preventing race conditions
 * where an older, slower request could overwrite newer results.
 */
@ExperimentalCoroutinesApi
class NewDomainSearchViewModelStaleRequestTest : BaseUnitTest() {
    @Mock
    private lateinit var analyticsTracker: AnalyticsTrackerWrapper

    @Mock
    private lateinit var repository: NewDomainsSearchRepository

    private lateinit var viewModel: NewDomainSearchViewModel

    @Before
    fun setUp() {
        MockitoAnnotations.openMocks(this)
        viewModel = NewDomainSearchViewModel(
            mainDispatcher = testDispatcher(),
            analyticsTracker = analyticsTracker,
            newDomainsSearchRepository = repository
        )
    }

    @Suppress("MaxLineLength")
    @Test
    fun `GIVEN multiple sequential searches WHEN searches complete THEN only latest result is shown in UI`() =
        test {
            val uiStates = mutableListOf<UiState>()
            val job = launch { viewModel.uiStateFlow.toList(uiStates) }

            val firstDomain = ProposedDomain(1, "a.com", "100", null, true)
            val secondDomain = ProposedDomain(2, "ab.com", "200", null, true)
            val thirdDomain = ProposedDomain(3, "abc.com", "300", null, true)

            whenever(repository.searchForDomains("a")).thenReturn(
                DomainsResult.Success(listOf(firstDomain))
            )
            whenever(repository.searchForDomains("ab")).thenReturn(
                DomainsResult.Success(listOf(secondDomain))
            )
            whenever(repository.searchForDomains("abc")).thenReturn(
                DomainsResult.Success(listOf(thirdDomain))
            )

            // Trigger searches with sufficient delay between them to trigger each one
            viewModel.onSearchQueryChanged("a")
            delay(300)
            viewModel.onSearchQueryChanged("ab")
            delay(300)
            viewModel.onSearchQueryChanged("abc")
            advanceUntilIdle()

            // Verify all searches were initiated
            verify(repository).searchForDomains("a")
            verify(repository).searchForDomains("ab")
            verify(repository).searchForDomains("abc")

            // Get final UI state - should only show results from the last search
            val populatedStates = uiStates.filterIsInstance<UiState.PopulatedDomains>()
            val finalState = populatedStates.last()

            // The final state should contain only the third (latest) search results
            assertThat(finalState.domains).containsExactly(thirdDomain)

            job.cancel()
        }

    @Suppress("MaxLineLength")
    @Test
    fun `GIVEN rapid sequential searches within debounce window WHEN search completes THEN only final search executes`() =
        test {
            val uiStates = mutableListOf<UiState>()
            val job = launch { viewModel.uiStateFlow.toList(uiStates) }

            val domain = ProposedDomain(1, "final.com", "100", null, true)

            whenever(repository.searchForDomains("final")).thenReturn(
                DomainsResult.Success(listOf(domain))
            )

            // Rapid changes within debounce window - only last should trigger search
            viewModel.onSearchQueryChanged("a")
            delay(100)
            viewModel.onSearchQueryChanged("ab")
            delay(100)
            viewModel.onSearchQueryChanged("abc")
            delay(100)
            viewModel.onSearchQueryChanged("final")
            advanceUntilIdle()

            // Only the final search should have executed
            verify(repository, times(1)).searchForDomains("final")

            // Earlier searches should not have been called
            verify(repository, times(0)).searchForDomains("a")
            verify(repository, times(0)).searchForDomains("ab")
            verify(repository, times(0)).searchForDomains("abc")

            // UI should show the final results
            val populatedStates = uiStates.filterIsInstance<UiState.PopulatedDomains>()
            assertThat(populatedStates.last().domains).containsExactly(domain)

            job.cancel()
        }

