    @Test
    fun `GIVEN new search triggered WHEN previous search in progress THEN previous search is cancelled`() =
        test {
            val uiStates = mutableListOf<UiState>()
            val job = launch { viewModel.uiStateFlow.toList(uiStates) }

            val firstDomain = ProposedDomain(1, "first.com", "100", null, true)
            val secondDomain = ProposedDomain(2, "second.com", "200", null, true)

            whenever(repository.searchForDomains("first")).thenReturn(
                DomainsResult.Success(listOf(firstDomain))
            )
            whenever(repository.searchForDomains("second")).thenReturn(
                DomainsResult.Success(listOf(secondDomain))
            )

